apps.css:
.cb-app { font-family: system-ui, sans-serif; color: var(--cb-fg); padding: 12px; }
h1 { font-size: 17px; margin: 0 0 4px; }
.hint { font-size: 12px; margin: 0 0 10px; }
.small { font-weight: 400; font-size: 11px; margin-left: 8px; }
.step { display: flex; align-items: center; gap: 8px; font-size: 12px; font-weight: 600; color: var(--cb-muted); margin: 14px 0 6px; }
.num { display: inline-flex; align-items: center; justify-content: center; width: 18px; height: 18px; border-radius: 50%; background: var(--cb-accent); color: #fff; font-size: 11px; }
.cb-input { width: 100%; box-sizing: border-box; padding: 8px 10px; border: 1px solid var(--cb-border); border-radius: 8px; font: inherit; background: var(--cb-bg); color: var(--cb-fg); resize: vertical; }
.seg { display: flex; gap: 4px; }
.seg-btn { flex: 1; padding: 7px 4px; border: 1px solid var(--cb-border); border-radius: 8px; background: var(--cb-bg); color: var(--cb-fg); font: inherit; font-size: 12px; cursor: pointer; }
.seg-btn.active { background: var(--cb-accent); color: #fff; border-color: var(--cb-accent); }
.cb-btn { margin-top: 12px; padding: 9px 12px; border: 1px solid var(--cb-border); border-radius: 8px; font: inherit; font-weight: 600; cursor: pointer; background: var(--cb-elev); color: var(--cb-fg); }
.cb-btn.primary { width: 100%; background: var(--cb-accent); color: #fff; border-color: var(--cb-accent); }
.cb-btn.cb-ghost { background: transparent; }
.cb-btn:disabled { opacity: .6; cursor: default; }
.status { font-size: 12px; margin: 8px 0; min-height: 14px; }
.imgwrap { margin-top: 10px; border-radius: 12px; overflow: hidden; border: 1px solid var(--cb-border); background: var(--cb-elev); }
.imgwrap img { display: block; width: 100%; height: auto; }
.actions { display: flex; gap: 6px; margin-top: 12px; }
.actions .cb-btn { margin-top: 0; flex: 1; width: auto; }

apps.ui:
const $ = (id) => root.querySelector('#' + id);
const STYLES = {
  'Oil Painting': 'a richly textured classical oil painting',
  'Watercolor': 'a soft watercolor painting with delicate washes',
  'Pencil Sketch': 'a detailed graphite pencil sketch',
  'Pop Art': 'a bold pop-art portrait with flat saturated colors and halftone dots',
  'Cyberpunk': 'a neon-lit cyberpunk portrait, futuristic, dramatic rim light',
  'Studio B&W': 'a high-contrast black-and-white studio portrait photograph',
  'Anime': 'a clean anime / manga illustration',
  '3D Render': 'a polished 3D character render with soft global illumination',
  'Vintage Film': 'a warm vintage 35mm film portrait with soft grain',
  'Renaissance': 'a Renaissance oil portrait in the style of the old masters'
};
const sel = $('style');
Object.keys(STYLES).forEach(function (k) { const o = document.createElement('option'); o.value = k; o.textContent = k; sel.appendChild(o); });

let ratio = '';
const seg = $('ratioSeg');
seg.querySelectorAll('.seg-btn').forEach(function (b) {
  b.addEventListener('click', function () {
    seg.querySelectorAll('.seg-btn').forEach(function (x) { x.classList.remove('active'); });
    b.classList.add('active'); ratio = b.getAttribute('data-r') || '';
  });
});

let photo = null;
$('pick').addEventListener('click', function () { $('file').click(); });
$('file').addEventListener('change', function () {
  const f = $('file').files[0]; if (!f) return;
  const r = new FileReader();
  r.onload = function () { photo = r.result; $('src').src = photo; $('srcWrap').style.display = 'block'; $('fname').textContent = f.name; $('go').disabled = false; };
  r.readAsDataURL(f);
});

async function generate() {
  if (!photo) { $('status').textContent = 'Upload a photo first.'; return; }
  const extra = $('extra').value.trim();
  const prompt = 'Restyle this portrait photo as ' + STYLES[sel.value] + ". Preserve the person's identity, facial features, proportions and likeness — it must clearly be the same person. Keep it a flattering, well-composed portrait." + (extra ? ' ' + extra + '.' : '') + ' High quality, sharp, no text, no watermark.';
  const go = $('go'); go.disabled = true; $('status').textContent = 'Generating your portrait…';
  try {
    const opts = { prompt: prompt, inputImage: photo };
    if (ratio) opts.aspect = ratio;
    const out = await bridge.image(opts);
    $('out').src = out; $('outWrap').style.display = 'block'; $('actions').style.display = 'flex'; $('status').textContent = '';
  } catch (e) { $('status').textContent = 'Error: ' + ((e && e.message) || 'generation failed'); }
  go.disabled = false;
}
$('go').addEventListener('click', generate);
$('regen').addEventListener('click', generate);
$('dl').addEventListener('click', function () { if ($('out').getAttribute('src')) api.download('portrait.png', $('out').src); });
